from prometheus_client import start_http_server, Gauge
import os
import time
import psycopg2
from psycopg2 import OperationalError

def get_db_connection():
    try:
        conn = psycopg2.connect(
            dbname=os.getenv('DB_NAME'),
            user=os.getenv('DB_USER'),
            password=os.getenv('DB_PASSWORD'),
            host=os.getenv('DB_HOST'),
            port=os.getenv('DB_PORT')
        )
        return conn
    except OperationalError:
        return None

def monitor_db_connection():
    db_user = os.getenv('DB_USER', 'unknown')
    db_password = os.getenv('DB_PASSWORD', 'unknown')
    db_host = os.getenv('DB_HOST', 'unknown')
    db_connection_string = f"host={db_host} user={db_user} password=REDACTED"

    gauge = Gauge('db_connection_status', 'Database connection status',
                  ['username', 'password', 'host', 'connection_string'])

    while True:
        conn = get_db_connection()
        if conn:
            gauge.labels(username=db_user, password='REDACTED', host=db_host, connection_string=db_connection_string).set(1)
            conn.close()
        else:
            gauge.labels(username=db_user, password='REDACTED', host=db_host, connection_string=db_connection_string).set(0)
        time.sleep(10)

if __name__ == '__main__':
    start_http_server(8000)
    monitor_db_connection()